namespace MyApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _store = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed initial fake data
        for (var i = 0; i < 5; i++)
        {
            _store.Add(new Notification(
                _nextId++,
                $"Welcome notification #{i + 1}",
                DateTime.UtcNow.AddMinutes(-10 + i)));
        }
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock) return _store.OrderByDescending(n => n.Timestamp).ToList();
    }

    /// <summary>Returns notifications created after the given id.</summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
            return _store
                .Where(n => n.Id > lastSeenId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
    }

    /// <summary>
    /// Simulates new notifications arriving.
    /// Call this from a hosted service or just let the polling demo
    /// generate items on demand.
    /// </summary>
    public Notification Add(string message)
    {
        lock (_lock)
        {
            var n = new Notification(_nextId++, message, DateTime.UtcNow);
            _store.Add(n);
            return n;
        }
    }

    /// <summary>Generates a random notification (used by the polling demo).</summary>
    public Notification GenerateRandom()
    {
        string[] templates =
        [
            "New comment on your post",
            "Your build succeeded",
            "Deployment to production complete",
            "New follower added",
            "PR review requested",
            "Issue assigned to you",
            "Disk usage warning",
            "Scheduled job finished",
        ];

        var msg = templates[Random.Shared.Next(templates.Length)]
                  + $" (#{Random.Shared.Next(1000):D3})";
        return Add(msg);
    }
}

@page "/notifications"
@rendermode InteractiveServer

@using MyApp.Services
@using Microsoft.AspNetCore.Components

@inject NotificationService Svc
@inject PersistentComponentState PersistentState

@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;

    protected override void OnInitialized()
    {
        // During prerender the state won't exist yet, so we load from the service.
        // On the interactive re-render, TryTake succeeds and we skip the service call,
        // avoiding a double-fetch.
        if (!PersistentState.TryTakeFromJson<List<Notification>>(
                "notifications", out var restored))
        {
            _notifications = Svc.GetAll();
        }
        else
        {
            _notifications = restored!;
        }

        // Register a callback so the prerender pass persists the data for the
        // interactive pass to pick up.
        _persistSub = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("notifications", _notifications);
            return Task.CompletedTask;
        });
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // OnAfterRender is never called during static SSR — it only fires
        // once the component is live on the circuit, so this is the safe
        // place to start the polling loop.
        if (!firstRender) return;

        _cts = new CancellationTokenSource();
        _ = PollForNotificationsAsync(_cts.Token);

        await Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        // Simulate external arrivals by generating a random notification each cycle.
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            // Simulate a new notification arriving on the server side
            Svc.GenerateRandom();

            var lastId = _notifications.Count > 0
                ? _notifications.Max(n => n.Id)
                : 0;

            var newer = Svc.GetSince(lastId);
            if (newer.Count > 0)
            {
                // Prepend new items (already sorted descending)
                _notifications.InsertRange(0, newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _persistSub.Dispose();

        // Cancel the polling loop so no fire-and-forget task leaks.
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

